SELECT ?movie ?title WHERE {
  ?movie wdt:P31 wd:Q11424;
         wdt:P276 wd:Q367466;
         wdt:P577 ?releaseDate.
  ?movie rdfs:label ?title.
  FILTER (lang(?title) = 'en').
  FILTER (?releaseDate > "2010-12-31T23:59:59Z"^^xsd:dateTime)
  FILTER EXISTS {?movie wdt:P38 []}
}
LIMIT 5

SELECT ?movie ?title ?boxOffice WHERE {
  ?movie wdt:P31 wd:Q11424;
         wdt:P272 wd:Q367466;
         wdt:P577 ?releaseDate;
         wdt:P38 ?boxOffice.
  ?movie rdfs:label ?title.
  FILTER (lang(?title) = 'en').
  FILTER (YEAR(?releaseDate) > 2010)
}
ORDER BY DESC(?boxOffice)
LIMIT 10

SELECT ?movie ?title ?boxOffice WHERE {
  ?movie wdt:P272 wd:Q367466;
         wdt:P577 ?releaseDate;
         wdt:P38 ?boxOffice.
  ?movie wdt:P31/wdt:P279* wd:Q11424.
  ?movie rdfs:label ?title.
  FILTER (lang(?title) = 'en').
  FILTER (YEAR(?releaseDate) > 2010)
}
ORDER BY DESC(?boxOffice)
LIMIT 10

